1	type Item = { type: string; material?: string; cursed?: boolean; enchantment?: number };
2	type Damage = { itemType: string; amount: number };
3	type Incident = { cause: string; damages: Damage[] };
4	type QuoteStep = { op: "quote"; items: Item[] };
5	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
6	type Step = QuoteStep | ClaimStep;
7	type Customer = { yearsWithMHPCO: number };
8	type Input = { customer: Customer; steps: Step[] };
9	
10	const PROCESSING_FEE = 5;
11	const FIRST_INSURANCE_SURCHARGE_PERCENT = 10;
12	const CURSE_SURCHARGE_PERCENT = 50;
13	const HIGH_ENCHANTMENT_THRESHOLD = 5;
14	const HIGH_ENCHANTMENT_SURCHARGE_PERCENT = 30;
15	const LOYALTY_THRESHOLD_YEARS = 2;
16	const LOYALTY_DISCOUNT_PERCENT = 20;
17	const FOLLOWUP_CONTRACT_DISCOUNT_PERCENT = 15;
18	const COMPONENT_BLOCK_SIZE = 3;
19	const COMPONENT_BLOCK_PREMIUM = 60;
20	const DEDUCTIBLE = 100;
21	const CAP_MULTIPLIER = 2;
22	
23	const INSURANCE_VALUE_BY_TYPE: Record<string, number> = {
24	  sword: 1000,
25	  amulet: 600,
26	  staff: 800,
27	  potion: 400,
28	  rune: 250,
29	  moonstone: 250,
30	};
31	
32	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
33	  sword: 100,
34	  amulet: 60,
35	  staff: 80,
36	  potion: 40,
37	  rune: 25,
38	  moonstone: 25,
39	};
40	
41	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
42	
43	const groupBaseAmount = (type: string, count: number): number => {
44	  if (COMPONENT_TYPES.has(type) && count === COMPONENT_BLOCK_SIZE) {
45	    return COMPONENT_BLOCK_PREMIUM;
46	  }
47	  return count * BASE_PREMIUM_BY_TYPE[type];
48	};
49	
50	const countByType = (items: Item[]): Map<string, number> =>
51	  items.reduce(
52	    (counts, { type }) => counts.set(type, (counts.get(type) ?? 0) + 1),
53	    new Map<string, number>(),
54	  );
55	
56	const basePremium = (items: Item[]): number =>
57	  Array.from(countByType(items)).reduce(
58	    (total, [type, count]) => total + groupBaseAmount(type, count),
59	    0,
60	  );
61	
62	const percentOf = (amount: number, percent: number): number =>
63	  (amount * percent) / 100;
64	
65	const percentOfItemBase = (item: Item, percent: number): number =>
66	  percentOf(BASE_PREMIUM_BY_TYPE[item.type], percent);
67	
68	const firstInsuranceSurcharge = (base: number): number =>
69	  percentOf(base, FIRST_INSURANCE_SURCHARGE_PERCENT);
70	
71	type ItemSurchargeRule = { applies: (item: Item) => boolean; percent: number };
72	
73	const ITEM_SURCHARGE_RULES: ItemSurchargeRule[] = [
74	  { applies: (item) => item.cursed === true, percent: CURSE_SURCHARGE_PERCENT },
75	  { applies: (item) => (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD, percent: HIGH_ENCHANTMENT_SURCHARGE_PERCENT },
76	];
77	
78	const surchargesForItem = (item: Item): number =>
79	  ITEM_SURCHARGE_RULES.reduce(
80	    (sum, { applies, percent }) => sum + (applies(item) ? percentOfItemBase(item, percent) : 0),
81	    0,
82	  );
83	
84	const itemSurcharges = (items: Item[]): number =>
85	  items.reduce((sum, item) => sum + surchargesForItem(item), 0);
86	
87	const policySurcharges = (items: Item[], base: number): number =>
88	  itemSurcharges(items) + firstInsuranceSurcharge(base);
89	
90	type PolicyContext = { customer: Customer; stepIndex: number };
91	type PolicyDiscountRule = { applies: (ctx: PolicyContext) => boolean; percent: number };
92	
93	const POLICY_DISCOUNT_RULES: PolicyDiscountRule[] = [
94	  { applies: ({ customer }) => customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS, percent: LOYALTY_DISCOUNT_PERCENT },
95	  { applies: ({ stepIndex }) => stepIndex > 0, percent: FOLLOWUP_CONTRACT_DISCOUNT_PERCENT },
96	];
97	
98	const policyDiscounts = (base: number, ctx: PolicyContext): number =>
99	  POLICY_DISCOUNT_RULES.reduce(
100	    (sum, { applies, percent }) => sum + (applies(ctx) ? percentOf(base, percent) : 0),
101	    0,
102	  );
103	
104	const quotePremium = (items: Item[], ctx: PolicyContext): number => {
105	  const base = basePremium(items);
106	  const surcharges = policySurcharges(items, base);
107	  const discounts = policyDiscounts(base, ctx);
108	  return Math.ceil(base + surcharges - discounts + PROCESSING_FEE);
109	};
110	
111	const insuranceSum = (items: Item[]): number =>
112	  items.reduce((sum, { type }) => sum + INSURANCE_VALUE_BY_TYPE[type], 0);
113	
114	const policyCap = (items: Item[]): number => CAP_MULTIPLIER * insuranceSum(items);
115	
116	const damagePayout = (damage: Damage): number => Math.max(0, damage.amount - DEDUCTIBLE);
117	
118	type Policy = { items: Item[]; remainingCap: number };
119	
120	type StepResult = { premium: number } | { payout: number; remainingCap: number };
121	
122	const processQuote = (step: QuoteStep, ctx: PolicyContext, policies: Policy[]): StepResult => {
123	  policies.push({ items: step.items, remainingCap: policyCap(step.items) });
124	  return { premium: quotePremium(step.items, ctx) };
125	};
126	
127	const processClaim = (step: ClaimStep, policies: Policy[]): StepResult => {
128	  const policy = policies[step.policy];
129	  const requested = step.incident.damages.reduce((sum, d) => sum + damagePayout(d), 0);
130	  const payout = Math.min(requested, policy.remainingCap);
131	  policy.remainingCap -= payout;
132	  return { payout: Math.floor(payout), remainingCap: policy.remainingCap };
133	};
134	
135	export const run = (input: unknown): unknown => {
136	  const { customer, steps } = input as Input;
137	  const policies: Policy[] = [];
138	  const results = steps.map((step, stepIndex): StepResult =>
139	    step.op === "quote"
140	      ? processQuote(step, { customer, stepIndex }, policies)
141	      : processClaim(step, policies),
142	  );
143	  return { results };
144	};
