const damagePayout = (damage: Damage): number => Math.max(0, damage.amount - DEDUCTIBLE);

const totalRequestedPayout = (damages: Damage[]): number =>
  damages.reduce((sum, damage) => sum + damagePayout(damage), 0);

type Policy = { items: Item[]; remainingCap: number };

type StepResult = { premium: number } | { payout: number; remainingCap: number };

const processQuote = (step: QuoteStep, ctx: PolicyContext, policies: Policy[]): StepResult => {
  policies.push({ items: step.items, remainingCap: policyCap(step.items) });
  return { premium: quotePremium(step.items, ctx) };
};

const processClaim = (step: ClaimStep, policies: Policy[]): StepResult => {
  const policy = policies[step.policy];
  const payout = Math.min(totalRequestedPayout(step.incident.damages), policy.remainingCap);
  policy.remainingCap -= payout;
  return { payout: Math.floor(payout), remainingCap: policy.remainingCap };
};
